import React, { useState } from 'react';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import { X, MapPin, Store } from 'lucide-react';

function LocationMarker({ position, setPosition }) {
  useMapEvents({
    click(e) {
      setPosition([e.latlng.lat, e.latlng.lng]);
    },
  });
  return position ? <Marker position={position} /> : null;
}

const ModalNuevaSucursal = ({ onClose, onSave }) => {
  const [datos, setDatos] = useState({
    nombre: '',
    provincia: 'Tucumán',
    ciudad: '',
    zona: '',
    direccion: ''
  });
  const [coords, setCoords] = useState([-26.816, -65.216]);

  const ubicacionesData = {
    'Tucumán': {
      'San Miguel de Tucumán': ['Centro', 'Barrio Norte', 'Barrio Sur', 'Villa Luján'],
      'Yerba Buena': ['Casco Viejo', 'San José', 'Cerca del Shopping', 'Av. Perón'],
      'Tafí Viejo': ['Centro', 'Lomas de Tafí', 'Villa Mitre']
    },
    'Salta': {
      'Salta Capital': ['Centro', 'Tres Cerritos', 'Grand Bourg'],
      'Cafayate': ['Centro', 'Zona Viñedos']
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!datos.ciudad || !datos.zona) return alert("Por favor completa Ciudad y Zona");
    onSave({ ...datos, coords });
  };

  return (
    <div style={modalOverlay}>
      <div style={modalContent}>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '15px' }}>
          <h3 style={{ margin: 0 }}><Store size={20} color="#e67e22" /> Registrar Local</h3>
          <X onClick={onClose} style={{ cursor: 'pointer' }} />
        </div>

        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
          <input 
            placeholder="Nombre del Comercio" style={inputStyle} required 
            value={datos.nombre} onChange={e => setDatos({...datos, nombre: e.target.value})}
          />

          <div style={{ display: 'flex', gap: '10px' }}>
            <select 
              style={inputStyle} value={datos.provincia} 
              onChange={e => setDatos({...datos, provincia: e.target.value, ciudad: '', zona: ''})}
            >
              {Object.keys(ubicacionesData).map(p => <option key={p} value={p}>{p}</option>)}
            </select>

            <select 
              style={inputStyle} required value={datos.ciudad}
              onChange={e => setDatos({...datos, ciudad: e.target.value, zona: ''})}
            >
              <option value="">Ciudad</option>
              {Object.keys(ubicacionesData[datos.provincia] || {}).map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>

          <select 
            style={inputStyle} required value={datos.zona}
            onChange={e => setDatos({...datos, zona: e.target.value})}
          >
            <option value="">Selecciona Zona / Barrio</option>
            {(ubicacionesData[datos.provincia][datos.ciudad] || []).map(z => <option key={z} value={z}>{z}</option>)}
          </select>

          <input 
            placeholder="Dirección Exacta (ej: Av. Alem 123)" style={inputStyle} required 
            value={datos.direccion} onChange={e => setDatos({...datos, direccion: e.target.value})}
          />

          <p style={{ fontSize: '0.75rem', color: '#64748b', margin: 0 }}>
            <MapPin size={12} /> Toca el mapa para ubicar el pin:
          </p>
          
          <div style={{ height: '150px', borderRadius: '10px', overflow: 'hidden' }}>
            <MapContainer center={coords} zoom={13} style={{ height: '100%' }}>
              <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
              <LocationMarker position={coords} setPosition={setCoords} />
            </MapContainer>
          </div>

          <button type="submit" style={btnSubmitModal}>Guardar y Activar Local</button>
        </form>
      </div>
    </div>
  );
};

const modalOverlay = { position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(0,0,0,0.7)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 3000 };
const modalContent = { background: 'white', padding: '25px', borderRadius: '20px', width: '450px' };
const inputStyle = { width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #cbd5e1', boxSizing: 'border-box' };
const btnSubmitModal = { width: '100%', padding: '12px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer' };

export default ModalNuevaSucursal;
